-- Seed data: Blog posts
INSERT INTO blog_posts (id, slug, title, excerpt, category, read_time, emoji, bg_color, author, date, body) VALUES
  ('b0010000-0000-4000-8000-000000000001', 'perfect-jollof-rice', 'The secret to party-style Jollof rice', 'Smoky, deeply flavoured and never mushy — the steps Nigerian aunties keep close to chest.', 'Recipes', '6 min read', '🍚', '#F4E4C8', 'Adaeze O.', '12 June 2026',
   '["There is a sound that defines a Nigerian celebration: the soft scrape of a wooden spoon against a heavy pot of jollof rice, and the smell of slightly charred bottom — the bottom-pot — drifting through the kitchen.","Party jollof is not the same dish you would cook on a Tuesday evening. It is bolder, smokier and built in layers, and almost every step is about coaxing more flavour into the grain.","Start with the base. Roast your tomatoes, red peppers and scotch bonnets until the skins blister, then blitz them with onion into a smooth purée. Reduce that purée hard in oil — it should look thick, glossy and just slightly darker before you add stock.","Use parboiled long-grain rice. The grain has been steamed before drying, which means it stays separated under long cooking and absorbs flavour without turning to porridge.","Cover the pot. Lower the heat to the smallest flame your hob will hold. Do not stir. The rice at the bottom will catch and create the charred crust — leave it. After thirty minutes, turn off the heat and let the pot sit, lid on, for ten more minutes.","Fluff gently, taste, and serve with fried plantain and pepper stew chicken. Send the leftover bottom-pot to whoever you love most."]'),
  ('b0010000-0000-4000-8000-000000000002', 'egusi-soup-guide', 'Egusi soup: a complete beginner''s guide', 'From grinding the seeds to balancing the pepper — make a pot that tastes like home.', 'Recipes', '8 min read', '🟡', '#FBF4D9', 'Tunde A.', '5 June 2026',
   '["Egusi is one of the most forgiving soups in the West African pantry. The melon seed thickens almost anything, and the soup tastes a little different in every household — which is exactly the point.","Buy your egusi pre-ground if you can. If not, a clean coffee grinder works in short pulses. You want a fine, slightly oily powder, not a paste.","Start by frying chopped onions in palm oil until softened. Slowly stir in the ground egusi, breaking up clumps, until it forms little curds in the oil. This is the moment your soup gains body.","Add stock — meat stock, fish stock, or both — slowly, and let the egusi loosen and bubble. Drop in your protein: smoked fish, stockfish, or pre-cooked goat meat. Season with bouillon, dried crayfish, salt and chilli to taste.","Finish with bitter leaf or pumpkin leaves, just until they wilt. Serve hot with eba, pounded yam or fufu, and a glass of cold water on the side."]'),
  ('b0010000-0000-4000-8000-000000000003', 'uk-african-shopping', 'Where to find African groceries in the UK (besides us)', 'An honest map of African markets and corner shops worth visiting in the major cities.', 'Community', '4 min read', '🛍️', '#E4F7EC', 'Adaeze O.', '29 May 2026',
   '["We love sending parcels, but sometimes you want to walk into a shop and pick your own scotch bonnets. Here is where we send our own friends and family when they ask.","In London, head to Peckham High Street for general African groceries, Ridley Road in Dalston for cheap produce, and Walthamstow for excellent halal frozen meats.","In Birmingham, Soho Road has a long stretch of well-stocked African and Caribbean shops. In Manchester, Cheetham Hill is the go-to. In Leeds, try Harehills.","Outside the big cities, look for Nigerian-owned restaurants — they often have a small shop attached, or will tell you which van does the regional delivery run.","And of course, when nobody is nearby and you need stockfish in a hurry, we will bring it to you."]'),
  ('b0010000-0000-4000-8000-000000000004', 'suya-spice-deep-dive', 'Inside a tin of suya spice', 'Yaji, peanut, ginger, clove — the chemistry behind the smell of every Lagos street corner.', 'Ingredients', '5 min read', '🌶️', '#F4ECFB', 'Tunde A.', '21 May 2026',
   '["Suya spice — yaji — is not a single recipe. Every mai suya guards his blend, and every region tweaks the balance. But the structure is shared.","The backbone is roasted, ground peanut — kuli kuli powder if you have it. It carries the spice and clings to grilled meat.","Heat comes from ground dry red pepper. Aroma comes from ginger, clove, and sometimes a little garlic granule. Salt and bouillon round it off.","The trick is in the order: meat goes onto a thin film of oil, then dusted heavily with yaji halfway through grilling so the spices toast without burning.","We sell our blend pre-mixed in 200 g tins. It will outlast the season — but probably won''t."]'),
  ('b0010000-0000-4000-8000-000000000005', 'stockfish-explained', 'Why stockfish costs what it costs', 'Sun, salt, time and a long boat ride from Norway. The economics of a soup essential.', 'Ingredients', '5 min read', '🐟', '#E4F3F7', 'Adaeze O.', '14 May 2026',
   '["Stockfish — okporoko in Igbo — is dried cod, traditionally hung on wooden racks in cold Norwegian air for three months. The drying concentrates the flavour into something almost meaty.","Norway sells the bulk of its export-grade stockfish to West Africa, and the supply chain has more stops than people realise: trawler, drying rack, sorting, shipping, customs, wholesaler, importer, retailer.","Each stop takes a cut. By the time a clean, head-on medium stockfish reaches a London shelf, it has crossed three borders.","What you pay for is the time — months of slow drying — and the cold-chain logistics that keep the fish dry on a wet sea voyage.","Cook it patiently. Soak overnight, simmer until soft, and pull the flesh away from the bone in big flakes. It transforms egusi, ogbono and pepper soup in ways nothing else can."]'),
  ('b0010000-0000-4000-8000-000000000006', 'diaspora-cooking-shortcuts', '10 diaspora cooking shortcuts that actually work', 'Air-fryer plantain, blender pepper mix, batch pre-fried meat — kitchen hacks from London Naijas.', 'Tips', '7 min read', '⚡', '#FBE7DC', 'Tunde A.', '8 May 2026',
   '["Cooking African food in a small UK kitchen, after a long shift, is a different sport than cooking at home in Lagos. Here are the shortcuts our community swears by.","Blend a big batch of pepper-tomato-onion base on a Sunday and freeze in ice cube trays. Pop two cubes into anything that wants stew.","Pre-fry your meat in bulk and freeze. When it is time to cook, the meat finishes in twenty minutes instead of ninety.","Use a rice cooker for jollof. It is not heresy — it is great. The bottom-pot still forms, and you can walk away.","Air-fryer plantain at 180°C for 12 minutes, flipped once. No oil, no mess, perfectly soft inside.","Buy ground egusi, ground crayfish and ground pepper. The flavour-per-minute is unbeatable.","Keep a single carton of palm oil, a tin of corned beef, a pack of indomie and a jar of locust beans in reserve. Dinner is always one combination away."]')
ON CONFLICT (slug) DO NOTHING;

-- Seed data: Recipes
INSERT INTO recipes (id, slug, title, time, serves, level, emoji, bg_color, intro, ingredients, steps) VALUES
  ('d0010000-0000-4000-8000-000000000001', 'jollof', 'Party Jollof Rice', '1h 30m', 6, 'Medium', '🍚', '#F4E4C8',
   'Smoky, party-style jollof made the long way. Made with parboiled long-grain rice, a slow-reduced pepper base and just the right amount of bottom-pot.',
   '[{"name":"Parboiled long-grain rice","productId":"a0010000-0000-4000-8000-000000000001","amount":"750 g"},{"name":"Red palm oil","productId":"a0010000-0000-4000-8000-000000000002","amount":"120 ml"},{"name":"Jollof seasoning cubes","productId":"a0010000-0000-4000-8000-000000000005","amount":"3 cubes"},{"name":"Plum tomatoes","amount":"5 medium"},{"name":"Red bell peppers","amount":"2 large"},{"name":"Scotch bonnets","amount":"2 (or to taste)"},{"name":"Onion","amount":"1 large + half for garnish"},{"name":"Chicken or beef stock","amount":"750 ml"},{"name":"Bay leaves","amount":"2"},{"name":"Curry powder, thyme, salt","amount":"to taste"}]',
   '["Blend tomatoes, peppers, scotch bonnets and onion into a smooth purée. Reduce over medium heat until thick and dark — about 20 minutes.","Heat palm oil in a heavy pot. Add chopped onion and fry until golden. Add the reduced pepper purée and fry until oil separates.","Stir in bouillon, curry powder, thyme and bay leaves. Add stock and bring to a boil.","Rinse the rice once. Add to the pot, stir gently, then cover with foil and a tight lid.","Drop heat to the lowest setting. Cook undisturbed for 25 minutes. Do not lift the lid.","Fluff gently, scrape up the bottom-pot, and serve with fried plantain."]'),
  ('d0010000-0000-4000-8000-000000000002', 'egusi', 'Egusi Soup', '1h', 4, 'Easy', '🟡', '#FBF4D9',
   'A soft, savoury melon-seed soup thickened with ground egusi and finished with bitter leaf. Serve with eba or pounded yam.',
   '[{"name":"Ground egusi seeds","productId":"a0010000-0000-4000-8000-000000000007","amount":"300 g"},{"name":"Red palm oil","productId":"a0010000-0000-4000-8000-000000000002","amount":"150 ml"},{"name":"Dried stockfish","productId":"a0010000-0000-4000-8000-000000000011","amount":"100 g, pre-soaked"},{"name":"Beef or goat meat","amount":"400 g, pre-cooked with stock"},{"name":"Onion","amount":"1 medium, chopped"},{"name":"Dried crayfish","amount":"2 tbsp ground"},{"name":"Bitter leaf or pumpkin leaves","amount":"2 handfuls"},{"name":"Bouillon, salt, ground pepper","amount":"to taste"}]',
   '["Heat palm oil in a heavy pot. Fry onions until translucent.","Slowly stir in the ground egusi, breaking up clumps. Cook until small curds form in the oil.","Add meat stock gradually and let the soup loosen. Add pre-cooked meat and pre-soaked stockfish.","Season with crayfish, bouillon, salt and pepper. Simmer for 20 minutes, stirring occasionally.","Stir in the leaves at the end. Cook just until wilted. Taste and adjust seasoning.","Serve hot with swallow of your choice."]'),
  ('d0010000-0000-4000-8000-000000000003', 'suya', 'Beef Suya Skewers', '40m', 4, 'Easy', '🌶️', '#F4ECFB',
   'Street-style skewers, dusted heavily with yaji and grilled hot. Best eaten standing up with sliced onion and tomato.',
   '[{"name":"Beef rump or sirloin","amount":"600 g, sliced thin"},{"name":"Suya pepper spice","productId":"a0010000-0000-4000-8000-000000000008","amount":"4 tbsp"},{"name":"Vegetable oil","amount":"2 tbsp"},{"name":"Bamboo skewers","amount":"8, soaked"},{"name":"Onion + tomato + cucumber","amount":"to serve"}]',
   '["Thread the beef onto skewers in folds.","Brush lightly with oil, then dust generously with suya spice on both sides.","Grill on high heat for 4 minutes a side, dusting again halfway through.","Rest for 2 minutes. Serve with sliced raw onion, tomato and cucumber."]'),
  ('d0010000-0000-4000-8000-000000000004', 'moin-moin', 'Moin Moin', '1h 20m', 6, 'Medium', '🫘', '#EAF6E4',
   'Steamed bean pudding — soft, savoury and ridiculously satisfying.',
   '[{"name":"Honey beans, peeled","amount":"500 g"},{"name":"Red bell peppers","amount":"2"},{"name":"Scotch bonnet","amount":"1"},{"name":"Onion","amount":"1"},{"name":"Palm oil","productId":"a0010000-0000-4000-8000-000000000002","amount":"100 ml"},{"name":"Bouillon, salt, crayfish","amount":"to taste"},{"name":"Boiled egg or fish","amount":"optional"}]',
   '["Blend the peeled beans with peppers, onion and a little water into a thick smooth batter.","Stir in palm oil, crayfish, bouillon and salt. The batter should drop slowly from a spoon.","Ladle into greased moulds, ramekins or foil cups. Add a piece of boiled egg or fish if using.","Steam for 50 minutes over medium heat. Top up the water as needed.","Cool slightly, then unmould. Serve with bread, garri or alone."]'),
  ('d0010000-0000-4000-8000-000000000005', 'puff-puff', 'Puff Puff', '45m', 8, 'Easy', '🍩', '#FBEFE0',
   'Soft, slightly sweet, deep-fried dough balls. The most welcome guest at any party.',
   '[{"name":"Plain flour","amount":"500 g"},{"name":"Instant yeast","amount":"7 g sachet"},{"name":"Sugar","amount":"80 g"},{"name":"Warm water","amount":"350 ml"},{"name":"Pinch of salt + grated nutmeg","amount":""},{"name":"Vegetable oil for deep frying","amount":""}]',
   '["Mix flour, yeast, sugar, salt and nutmeg. Add warm water gradually until you get a thick, sticky batter.","Cover and let rise in a warm place for 45 minutes, until doubled and bubbly.","Heat oil to 170°C. Scoop balls of batter with a wet hand and drop carefully into the oil.","Fry 3–4 minutes, turning, until deep golden brown.","Drain on paper towel. Dust with sugar if you like. Serve immediately."]'),
  ('d0010000-0000-4000-8000-000000000006', 'pepper-soup', 'Catfish Pepper Soup', '50m', 4, 'Easy', '🐟', '#E4F3F7',
   'A clean, fiery, aromatic broth — the classic late-night Lagos comfort food.',
   '[{"name":"Fresh catfish, cleaned","amount":"1 kg, cut into steaks"},{"name":"Pepper soup spice mix","amount":"2 tbsp"},{"name":"Scotch bonnet","amount":"1, slit"},{"name":"Onion","amount":"1, sliced"},{"name":"Stock cubes","amount":"2"},{"name":"Scent leaves or basil","amount":"a handful"},{"name":"Salt","amount":"to taste"}]',
   '["Rinse the catfish steaks in hot salty water to firm them up. Drain.","Bring 1.2 litres of water to a boil. Add onion, scotch bonnet, pepper soup spice and stock cubes.","Simmer 5 minutes. Slip in the catfish steaks carefully — do not stir.","Cook 15 minutes until the flesh just turns opaque and pulls from the bone.","Stir in scent leaves at the very end. Serve hot in deep bowls with sliced yam or alone."]')
ON CONFLICT (slug) DO NOTHING;
